@org.springframework.stereotype.Service
class EventProducerService {

    private final KafkaProducer<String, String> producer;

    public EventProducerService(KafkaProducer<String, String> producer) {
        this.producer = producer;
    }

    public EventPublishResult send(String topic, String key, String payload, Map<String, String> userHeaders) {
        ProducerRecord<String, String> record = new ProducerRecord<>(topic, key, payload);
        Headers headers = record.headers();

        if (userHeaders != null) {
            userHeaders.forEach((headerKey, headerValue) -> {
                if (StringUtils.hasText(headerKey) && headerValue != null) {
                    headers.add(headerKey, headerValue.getBytes(StandardCharsets.UTF_8));
                }
            });
        }

        try {
            RecordMetadata metadata = producer.send(record).get();
            return new EventPublishResult(metadata.topic(), metadata.partition(), metadata.offset());
        } catch (Exception e) {
            throw new RuntimeException("Failed to publish event to Kafka", e);
        }
    }

    @PreDestroy
    public void shutdown() {
        producer.flush();
        producer.close();
    }
}

